query SiteQuery($siteId: String!, $accountId: String!) {
  site(siteId: $siteId, accountId: $accountId) {
    id
    url
    accessibilityCount
    latestStatsSnapshot {
      accessibility {
        score
        affectedPagesCount
      }
    }
  }
  assets(
    siteId: $siteId
    accountId: $accountId
    assetTypes: ["pdf"]
    page: 1
    perPage: 1
    sortBy: path
    sortOrder: asc
  ) {
    totalEntries
  }
}
